import{_ as r,o as S,c as e,j as p,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const P=JSON.parse('{"title":"SCP-7606","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/SCP-7606.md","filePath":"4.资源分区/6.技艺及称号/杂项/SCP-7606.md"}'),n={name:"4.资源分区/6.技艺及称号/杂项/SCP-7606.md"};function o(i,a,A,R,I,C){return S(),e("div",null,[...a[0]||(a[0]=[p("h1",{id:"scp-7606",tabindex:"-1"},[t("SCP-7606 "),p("a",{class:"header-anchor",href:"#scp-7606","aria-label":'Permalink to "SCP-7606"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),s('<h1 id="scp-7606-1" tabindex="-1">SCP-7606 <a class="header-anchor" href="#scp-7606-1" aria-label="Permalink to &quot;SCP-7606&quot;">​</a></h1><p>SCP-7606<br> 价格：SS+16000<br> 项目编号：SCP-7606<br> 收容等级：<br> esoteric<br> 次要等级：<br> apollyon<br> 扰动等级：<br> amida<br> 风险等级：<br> critical</p><p>特殊收容措施：<br> SCP-7606无法被杀死、伤害或受到任何程度阻碍。在目前的收容危机中，特工不得对峙SCP-7606，而应作为替代遏制情报外泄，减少被视为已损失的源头城市受到的破坏。若SCP-7606突破城市边界，帷幕协议将被解除，而后会立即开始准备应对一次HK级神性征服情景。</p><p>描述： SCP-7606是一名敌意神性实体，具有以下能力:<br>     对奇术仪式有超出人类详细掌握。<br>     无比的物理战斗技艺，同时掌握有多种古代军事技术，还有能力显现出其选定的任何武器。<br>     与火焰、黑暗及死亡之概念存在概念性关联，因而对其有完全的控制力。</p><p>SCP-7606于27/07/2022的09:44 CDT显现于基准现实，下列讲话开始向最初显现点周围5公里内所有知性存在以心灵感应方式广播：</p><p>听令罢虫子，速听我言；</p><p>我名为征服，</p><p>我名为荒芜，</p><p>我名DAV’VAHID MAEKALAH STRYGWYR。</p><p>汝等溃污我之领土久矣。</p><p>人所不知的亘古年间我一度沉眠；</p><p>而今我再度醒来，只见寄生虫败坏曾经归属于我的土地。</p><p>放下汝等兵器，如此可赐汝等速死。</p><p>屈服献身，汝等性命将注入全新天命。</p><p>截至目前，基金会能力范围内没有任何办法能有效反制SCP-7606。已调用所有相关部门研究员寻找SCP-7606的可能弱点或将其送回原本位面的方法。</p><p>在全体基金会资源被紧急激活的一小时后，基金会特工与SCP-7606发生短暂遭遇。下面是特工Trevor Garrison体载摄像机拍摄内容的抄录。</p><p>开始记录</p><p>视频拍摄于迈阿密城中心街道，基金会人员已在当地警方和美国军队协助下于此设置封锁。</p><p>GARRISON: 嘿。</p><p>镜头转向左侧，特工Raylan Davis正站在其他士兵及执法人员中间。</p><p>DAVIS: 咋。</p><p>GARRISON: 我们前面的封锁线没了。那边的人一看到7606就完了，我不知道其余人出了什么事情。</p><p>DAVIS: 耶？</p><p>GARRISON: 耶。</p><p>DAVIS: 所以接下来它就得来这里了？</p><p>GARRISON: 对。</p><p>记录中一片静默。</p><p>特工Davis叹气。</p><p>GARRISON: 说说你的感想？</p><p>DAVIS: 搞我是吧哥们…</p><p>GARRISON: 对。</p><p>DAVIS: 我是说至少平民都撤了。</p><p>GARRISON: (点头)这里就我们。</p><p>DAVIS: 就我们这帮垃圾在这。有那么多狗时间狗地方，不走运的垃圾刚刚好就被安到这里。</p><p>记录中一片静默。</p><p>DAVIS: 操！</p><p>特工Davis踢踹沙袋。</p><p>GARRISON: 唔。</p><p>DAVIS: 操我们所有人操！那么多狗地方怎么它就非得来这我操！</p><p>GARRISON: 我是说，这么多地方为何偏偏佛罗里达？</p><p>DAVIS: 妈的行吧。你怎么回事？你怎么这么冷静？</p><p>GARRISON: 之前给女朋友打过电话。集体违反安保但是谁还在乎。做了些告别，感觉像个狠人。</p><p>DAVIS: 哈。这确实听起来不错。</p><p>GARRISON: 此外，你想把人生最后一小时浪费在紧张上吗？</p><p>DAVIS: 这…非常真实。</p><p>GARRISON: 说起违反协议…</p><p>Garrison特工打开弹药盒，拿出两瓶迷你装的杰克丹尼威士忌。</p><p>DAVIS: 哈！耶稣基督你个Trev，你当真是全地球最聪明的人！</p><p>Garrison特工给Davis特工递来一瓶酒。</p><p>GARRISON: 致世界末日？</p><p>DAVIS: 致让我值了的那位杂种。</p><p>GARRISON: (嗤笑) 干杯吧Ray。</p><p>两名特工喝完酒，看向街道。</p><p>SCP-7606出现在远处。</p><p>DAVIS: 天耶稣基督这他妈怎么。</p><p>警报响起，所有战斗员跑向各自位置，拿起武器瞄准SCP-7606。SCP-7606继续逼近了几秒，而后开始缩减它与封锁线的距离。</p><p>镜头外传来恐慌的大叫，有多名士兵从封锁线逃跑。其余人，包括特工Garrison丢掉了步枪，开始急促喘息。</p><p>GARRISON: 操我们死定了。</p><p>DAVIS: 至少我们没有哭哭啼啼去死。</p><p>GARRISON: 我觉得也是…好在平民都走了我们—</p><p>一名老年白人（之后辨认出是Gary Stevenson）只穿着底裤从附近公寓楼里走出。</p><p>STEVENSON: 他妈了个基佬屁猴子逼玩意儿老子这鬼窗户外面闹什么动静？！</p><p>该平民正在重度迷醉中。</p><p>STEVENSON: 老子他妈的要睡觉！</p><p>平民注意到了SCP-7606。</p><p>STEVENSON: 什么鬼玩意？！</p><p>他从内裤里掏出一把柯尔特鲁格LCR左轮手枪，对着SCP-7606连开三枪，将其当场击毙。</p><p>记录中一片静默。</p><p>记录结束</p><p>更新：<br> SCP-7606是22岁的奇术师David Micheal Smith。Smith曾执行过一种能施加模因效应的仪式，任何观看或提及施法者的人都会受其影响。此效应会使人相信施法者是有恶魔起源的极端强力神性实体、无法被战胜，除非观察者已接受过对模因影响的先进治疗或反制措施。</p><p>从证据来看，此效应并不足以压制在致幻药物影响下的人类瞬时“战或逃”反应。</p><p>正在审议将SCP-7606变更类别为无效化。</p><p>效果：在购买并执行了该仪式后（这需要你执行一次长达12小时的奇术仪式，购买后自动获得相关知识），任何观看或提及到你的单位都会受其仪式带来的SS级模因效果影响，需要进行一次DC为96的意志豁免，失败则被仪式影响，使人相信购买者是有恶魔起源的极端强力神性实体、无法被战胜，会避开购买者及其指定的群体进行战斗，这是一个S级信息来源的支配效果，同样视为【模因】来源，但在以下几种情况中的单位不受此模因效果影响：</p><p>1.因为某些原因陷入混乱状态（如喝酒喝醉，嗑药磕出幻觉，或者患有严重癔症，精神类疾病，因例如为血癫狂等涉及到混乱，或是能力带来的负面作用导致的无差别攻击等效果）。<br> 2.处于任何情绪异常点数导致的严重状态（即使是恐惧异常点数导致的严重状态，只要来源不是你，就能忽略这一效果影响）<br> 3.被支配，胁迫等效果影响。</p><p>购买者在执行该仪式后，能够拥有一种心灵沟通能力，能够同时选择当前星球范围内的所有知性单位进行沟通并传达自己的精确定位，以此法传递信息也将让被接受者需要如同上述提及的效果一样，以意志豁免对抗DC来豁免效果，这是一个S级的心灵来源的信息共享效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',77)])])}const l=r(n,[["render",o]]);export{P as __pageData,l as default};
